import{_ as n,I as b,o as p,c as a,a4 as t,j as l,a as i,J as e,w as s}from"./chunks/framework.EYT3XhWU.js";const D=JSON.parse('{"title":"递进关系","description":"","frontmatter":{},"headers":[],"relativePath":"行测/言语理解/中心理解/递进关系.md","filePath":"行测/言语理解/中心理解/递进关系.md"}'),x={name:"行测/言语理解/中心理解/递进关系.md"},d={class:"details custom-block",open:"",style:{"box-sizing":"border-box",border:"1px solid rgba(0, 0, 0, 0)","border-radius":"8px",padding:"16px 16px 8px","line-height":"24px","font-size":"16px",color:"rgb(223, 223, 214)","background-color":"rgba(142, 150, 170, 0.14)",margin:"0px !important"}},g={start:"7",style:{"box-sizing":"border-box","list-style":"decimal",margin:"16px 0px",padding:"0px 0px 0px 1.25rem"}},w={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none"}},y={class:"details custom-block",open:"",style:{"box-sizing":"border-box",border:"1px solid rgba(0, 0, 0, 0)","border-radius":"8px",padding:"16px 16px 8px","line-height":"24px","font-size":"16px",color:"rgb(223, 223, 214)","background-color":"rgba(142, 150, 170, 0.14)",margin:"0px !important"}},m={start:"7",style:{"box-sizing":"border-box","list-style":"decimal",margin:"16px 0px",padding:"0px 0px 0px 1.25rem"}},z={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}},f={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}},k={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}};function v(u,o,c,C,B,A){const r=b("font");return p(),a("div",null,[o[15]||(o[15]=t('<h1 id="递进关系" tabindex="-1">递进关系 <a class="header-anchor" href="#递进关系" aria-label="Permalink to “递进关系”">​</a></h1><p>字数: 4633 字 时长: 17 分钟 <strong>VIP文档</strong></p><h2 id="一、什么是递进关系" tabindex="-1">一、什么是递进关系 <a class="header-anchor" href="#一、什么是递进关系" aria-label="Permalink to “一、什么是递进关系”">​</a></h2><ol><li><p><strong>1</strong>、递进关系指的是在一段文字中，后一句话/下一段与前一句话/上一段相比，在内容、意义或表达方式上有所增加或深化。</p><ol><li><blockquote><p>(1)他不但长得帅，而且有才华。 (2)结婚不仅需要车子，还需要房子，更重要的是需要一名结婚对象。</p></blockquote></li></ol></li></ol><h2 id="二、递进词" tabindex="-1">二、递进词 <a class="header-anchor" href="#二、递进词" aria-label="Permalink to “二、递进词”">​</a></h2><ol><li><p><strong>1、常用格式</strong>：不但……而且……</p></li><li><p><strong>2、替换词语</strong>：</p><ol><li>（1）不但=不仅、不单、不只、不光、不独</li><li>（2）而且=并且、并、也、还、甚至、更</li></ol></li><li><p><code>有些词既可以理解为并列关系，又可以理解为递进关系，不要机械地对待“并列”和“递进”，要结合具体的文段内容分析</code></p></li></ol><h2 id="三、解题技巧" tabindex="-1">三、解题技巧 <a class="header-anchor" href="#三、解题技巧" aria-label="Permalink to “三、解题技巧”">​</a></h2><ol><li><strong>1</strong>、当文段中出现表示递进的关联词时，递进关联词后的内容为重点。 <ol><li><code>例</code>：卢梭的名言“爱情不仅不能买，而且金钱必然会扼杀爱情”中。</li><li>递进词“而且”后半句的语气明显加重，强调了金钱对爱情的危害。</li></ol></li><li><strong>2</strong>、除此之外若出现“不但……而且……甚至……”这样的多重递进时，最后一层递进后的内容为重点。 <ol><li><code>例</code>：小红不但会唱歌，而且会跳舞，甚至钢琴也弹得特别好。</li><li>A.小红钢琴弹得非常好</li><li>B.小红多才多艺</li><li>最后一级递进之后是重点，因此选A，注意当选项没有多重递进之后的内容，此时应该选一个包含递进关系最全的选项，这是一个优选的原则。本题如果没有A选项应该优先选B。</li></ol></li><li><strong>3</strong>、程度词也是加强语气，它和递进关系的作用是一样的，所以把程度词归到递进关系中，程度词之后是重点。程度词：有意思的是...、重要的是...、有趣的是...、特别说明的是...、尤其是...等等 <ol><li><code>例</code>：小红会很多种才艺，最为突出的是她钢琴弹得特别好。本句强调了小红钢琴弹得特别好。</li></ol></li><li><strong>4</strong>、注意：需要区分递进与并列关系，递进强调的是递进后的内容，而并列则是提取共性，并列中的内容同样重要。</li></ol><h2 id="四、随笔练习" tabindex="-1">四、随笔练习 <a class="header-anchor" href="#四、随笔练习" aria-label="Permalink to “四、随笔练习”">​</a></h2><p><strong>例1</strong>：（2017国考）空气、水、土地 , 是人类赖以生存的三大必需条件。然而相对于大气污染和水环境污染 , 公众对土壤污染并不够重视 , 防治意识要弱很多。很大程度上是由于土壤污染具有隐蔽性、滞后性。雾霾来了我们能看到 , 河水变臭我们能闻到 , 可我们并不知道自己吃的大米、蔬菜是什么样的土里种出来的 , 含有什么不该有的元素。更可怕的是 , 土壤污染一旦发生便很难恢复，如果今年这片地里种出的庄稼有毒 , 明年也必定带毒 , 若想恢复如初 , 需要付出巨大代价以及漫长时间。</p><ol><li>这段文字意在强调（）</li><li>A. 土壤污染与其他生态污染有哪些不同</li><li>B. 公众应重视土壤污染并提高防治意识</li><li>C. 土壤污染危害的发现为何具有滞后性</li><li>D. 土壤污染治理应舍得投入时间和财力</li></ol>',11)),l("details",d,[l("ol",g,[l("li",w,[o[2]||(o[2]=i("文段为分—总结构，论述了跟空气和水的污染相比，土壤污染并没有引起人们的重视，通过",-1)),e(r,{color:"#6600CC",style:{"box-sizing":"border-box"}},{default:s(()=>[...o[0]||(o[0]=[i("递进强调了土壤污染如若发生恢复的难度非常大",-1)])]),_:1}),o[3]||(o[3]=i("，故整个文段结构为“提出问题—分析问题”，由此可知我们应当选择一个",-1)),e(r,{color:"#6600CC",style:{"box-sizing":"border-box"}},{default:s(()=>[...o[1]||(o[1]=[i("解决该问题的对策",-1)])]),_:1}),o[4]||(o[4]=i("，因此对比选项，B 选项符合文意。故本题选 B",-1))])])]),o[16]||(o[16]=l("p",null,[l("strong",null,"例2"),i("：（2018江苏）徽州古村落不同于一般的乡村 , 它在选址布局、人居理念、耕读文化、宗族承嗣、儒商精神等方面都发展到了较高的形态 , 有着中国传统文化的深厚积淀。亲历徽州的古村落 , 就像穿越了久远的时空 , 不仅感受到似水墨淡彩的自然风光 , 还能从乡村历史文化中领略到古人的生存智慧。")],-1)),o[17]||(o[17]=l("ol",null,[l("li",null,"根据文意，徽州古村落不同于一般的乡村主要在于其（）"),l("li",null,"A. 建筑美学"),l("li",null,"B. 历史积淀"),l("li",null,"C. 文化形态"),l("li",null,"D. 生存智慧")],-1)),l("details",y,[l("ol",m,[o[14]||(o[14]=l("li",{style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none"}},"从文段中寻找徽州古村落不同于一般乡村的主要原因。",-1)),l("li",z,[o[6]||(o[6]=i("第二步，分析文段。 第一句表达徽州古村落不同于一般乡村的原因在于有着",-1)),e(r,{color:"#6600CC",style:{"box-sizing":"border-box"}},{default:s(()=>[...o[5]||(o[5]=[i("中国传统文化的深厚积淀",-1)])]),_:1}),o[7]||(o[7]=i("。",-1))]),l("li",f,[o[9]||(o[9]=i("第二句重点在递进之后表达还能从",-1)),e(r,{color:"#6600CC",style:{"box-sizing":"border-box"}},{default:s(()=>[...o[8]||(o[8]=[i("乡村历史文化中领略到古人的生存智慧",-1)])]),_:1}),o[10]||(o[10]=i("。",-1))]),l("li",k,[o[12]||(o[12]=i("综合两句话重点都落在“",-1)),e(r,{color:"#6600CC",style:{"box-sizing":"border-box"}},{default:s(()=>[...o[11]||(o[11]=[i("文化",-1)])]),_:1}),o[13]||(o[13]=i("” 上，只有“文化形态”符合文意。因此，选择 C 选项。",-1))])])]),o[18]||(o[18]=t('<p><strong>例3</strong>：（2016北京）写作事实上不但是为了向外发表，贡献社会，同时也是研究工作的最后阶段，而且是最重要、最严肃的阶段。不形成文章，根本就没有完成研究工作，学问也没有成熟。常有人说：“某人学问极好，可惜不写作”，事实上，此话大有问题。某人可能学识丰富，也有见解，但不写作文，他的学问就只停留在简单看法的阶段，没有经过严肃的思考与整理，就不可能真正是系统的、成熟的。</p><ol><li>这段文字主要强调了：</li><li>A.论文写作的重要性</li><li>B.科学研究的首要目的</li><li>C.研究工作的评价标准</li><li>D.知识与实践的内在联系</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段首句通过程度词“最重要”“最严肃”引出作者观点，即写作对研究的重要性。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">接着从反面强调其重要性，最后又指出没有写作的学问是不成系统的，不成熟的，再次论证了写作的重要性，重在强调写作很重要，对应A项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">“写作”是文段的主题词，而B、C、D三项均未涉及“写作”，偏离文段中心，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为A。</li></ol></details><p><strong>例4</strong>：（2017广东国家税务）当人们谈到精神分裂症患者时，通常的反应仍是感到恐惧、不可思议和排斥、歧视，生活在真实社会、普通生活中的正常人是很难理解精神病患者的那些怪异行为和举止的。可是在我们的社会中，精神病人却是越来越多了，他们不仅需要得到医生和心理工作者的关注，还需要得到大众的认可和支持。</p><ol><li>这段话意在强调（ ）。</li><li>A.人们不应该歧视精神病患者</li><li>B.精神病人更需要大众的认可和支持</li><li>C.正常人无法理解精神病人</li><li>D.精神病人应该得到医生和心理工作者的关注</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="8" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">分析文段，第一句反映了人们对于精神分裂患者怪异行为的态度，通常是歧视、排斥甚至是恐惧。其后通过“可是”进行转折，故重点在第二句。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">“不仅仅…还”表示递进关系，故重点在递进之后，即强调大众对精神病人的认可和支持。B项是文段的同义替换，当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，没有具体指出“大众”的态度，表述不明确，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，非重点，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，递进前的内容，不是作者强调的重点，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例5</strong>：（2011内蒙古）历史曾为民族复兴之路留下许多珍贵的影像，但不论哪一帧历史的截影，似乎都不能直接放大成为一件历史主题的完美杰作。历史题材的美术作品作为一种历史的图像，当然对缺失的历史即是影像的弥补，但更重要的是一种符合历史逻辑与影像的艺术创造。一幅历史主题的美术作品，至少记载并浓缩了一个历史事件，也通过这个历史事件塑造了历史人物。</p><ol><li>这段文字意在说明，历史题材的美术作品应：</li><li>A.充分尊重并充分再现历史事实</li><li>B.在理解历史的基础上进行历史题材的创作</li><li>C.对历史人物及事件进行细致刻画</li><li>D.在还原历史的同时突出艺术感召力</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="8" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">分析文段。第一句话，“但”之后强调历史不能直接成为好的作品，转折词引出一个问题。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">“但”之后出现程度词“更重要的是”强调美术作品要符合历史逻辑与影像的重要性，给出对策。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">最后一句话补充论据全文，指出美术作品有弥补的作用。因此文段重点是程度词引导的“美术作品应符合历史逻辑与影像的艺术创造”。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项：缺少“艺术创造”。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项：理解历史是对“符合历史逻辑”的同义替换，进行历史题材的创作是对“艺术创造”的同义替换，B正确。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C、D项中的“细致刻画”“艺术感召力”文段中并未涉及，所以都排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例6</strong>：（2019浙江）传统工艺是在民间生活中创造的，无论是趋利避害、迎祥祈福的装饰还是家居日常的物件，传统工艺与日常生活融为一体，无处不在。如今，生活从传统走向现代，生活方式发生了不小的变化，但我们仍然需要传承这样的生活艺术和生活智慧，复兴工艺文化的创造力，创作生活之美。在现代经济全球一体化的背景下，文化更需要民族身份，不能因为生活方式的转变而放弃了文化的基因，丢失了民族的记忆，特别是传统工艺中所蕴含的“匠作精神”更是我们民族文化中宝贵的精神财富。</p><ol><li>该文段的主旨是（）</li><li>A.“生活之美”永流传</li><li>B.“匠作精神”不能丢</li><li>C.传统工艺的传承之路</li><li>D.传统工艺的生活美学</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段首先指出传统工艺与日常生活融为一体，接着指出生活方式发生变化的今天，还是需要传承传统工艺和生活智慧。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">紧接着通过程度词“更”强调文化需要民族身份，后面又通过程度词“特别是”、“更”强调“匠作精神”是民族文化中的瑰宝，不能丢。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故文段通过层层递进，强调的是“匠作精神”不能丢，对应到B项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“生活之美”属于程度词之前的内容，非重点，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项“传承之路”属于程度词之前的内容，非重点，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，“生活美学”对应文段中“创作生活之美”，属于程度词之前的内容，非重点，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例7</strong>：（2017新疆）街道老了必然面临改造的命运，但城市文化、城市味道未必不能保存和延续下来。仔细研究那些消失的地方特色美食、知名老店，会发现它们往往不是消失于“市场的选择”。对城市来说，不能只有看得见的光鲜、摸得着的利益、便于量化的经济增长指标，更需要市井的味道、城市的记忆、百姓的情感。</p><ol><li>这段文字意在强调（ ）。</li><li>A.老街是城市文化的重要载体</li><li>B.老街的消失是市场选择的结果</li><li>C.老街改造的理由不够充分</li><li>D.老街改造不能抹掉情感记忆</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="6" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段开篇指出老街道改造时未必不能保存城市文化、城市味道，接下来进行分析，指出“特色老店”往往不是消失于“市场的选择”。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">尾句提出对策，通过程度词“更”强调“城市需要市井的味道、百姓的情感等”。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故文段重点强调了老街道改造需保存百姓的情感、城市味道，对应D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“文化的重要载体”，文中并未提及，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，根据“它们往往不是消失于‘市场的选择’”可知表述有误，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，文段重点强调了“老街道改造需保存百姓的情感、城市味道”，而非“改造老街的理由”，故偏离文段中心，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><p><strong>例8</strong>：（2021新疆）从近些年中国电视节目的格局来看，综艺节目的几大模板几乎全部移植于国外，鲜有本土原创，文化传统和民族特质越来越淡，中国电视的本土化创新进入困境。实际上，早在十几年前，有识之士便开始呼吁电视媒体应在努力学习外国优秀节目经验的同时，更注重植根本土文化，在源远流长的中华文明中寻找创新的源动力。现在以《中国诗词大会》为代表的文化类节目的兴起，用特有的中国气派和较强的原创魅力，证明以传统文化助推电视节目创新的路径是可行的。</p><ol><li>这段文字意在强调中国的电视综艺节目：</li><li>A.应避免一味照搬国外模式</li><li>B.应以传统文化为创新源泉</li><li>C.应担负起发扬传统文化的责任</li><li>D.激发了观众对传统文化的兴趣</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="6" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">&quot;中国电视的本土化创新进入困境&quot;：文段开篇提出中国电视本土化创新有困难。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">后通过转折关联词“实际上”以及递进关联词“应...更...”引出核心对策，重点为“更注重植根本土文化，在源远流长的中华文明中寻找创新的源动力”。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">尾句以《中国诗词大会》进行举例说明，故文段为分总分结构。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">因此重点强调中国的电视综艺节目应以传统文化为创新源动力，对应B项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，文段强调中国的电视综艺节目应以传统文化为创新源泉，“避免一味照搬国外模式”表述不明确，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“发扬传统文化”文段并未提及，无中生有，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，“激发了观众对传统文化的兴趣”文段并未提及，无中生有，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例9</strong>：（2019山西管委会工作人员）在广大农村，教师收入普遍不高，更是凸显出教师的权利困境、待遇困境。头戴受人尊敬的光环，却不得不面临现实生活的窘境，常常给教师带来身份认同的撕裂。让教师真正成为“最受社会尊重的职业”，既需要教师涵养为师之德，具备仁爱之心，增强立德树人、教书育人的荣誉感和责任感。更需要国家给予教师更多的关怀，改善教师待遇，关心教师健康，维护教师权益。</p><ol><li>对这段文字的主旨概括最准确的是（ ）。</li><li>A.呼吁国家给予教师更多的关怀</li><li>B.说明教师职业的崇高性</li><li>C.介绍教师行业所面临的困境</li><li>D.说明教师职业的精神内涵</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="6" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段开篇指出在广大农村教师面临待遇不高的困境，接着给出对策，让教师成为最受社会尊重的职业，不仅仅需要涵养为师之德，更需要国家给予更多的关怀，“更”递进表强调，故文段的重点在最后，强调国家要给予教师更多的关怀。对应A项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，“崇高性”对应文段受人尊敬，非重点，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“困境”是背景引入段，描述问题，非重点，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，“精神内涵”对应文段荣誉感和责任感，非重点，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为A。</li></ol></details><p><strong>例10</strong>：（2022粉笔模考）由于很多普通消费者缺乏相关医学知识，对增高产品不了解，轻信商家的宣传，结果花钱购买使用增高产品后，轻则没有达到商家所宣传的增高效果，重则给身体健康带来危害。所以，面对增高产品乱象，消费者必须擦亮眼睛，避免被商家收割“智商税”。有关方面也应该把增高常识普及作为治理增高产品乱象的一味“药”，使消费者不再轻易相信增高产品宣传，而是在医生指导下进行食疗，或选择适宜的增高产品。更重要的是，应该让“吹牛”商家吃“罚药”。根据《广告法》规定，广告不得含有虚假或者引人误解的内容，不得欺骗、误导消费者等。凡违反规定的，应受到处罚。</p><ol><li>该文段意在说明：</li><li>A.消费者应提高对增高产品的防范意识</li><li>B.滥用增高产品或对身体造成严重损害</li><li>C.普及医学常识有利于消费者理性消费</li><li>D.治理增高乱象需对违法商家实施处罚</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="6" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">文段首先指出了许多消费者购买增高产品引发了各种问题甚至危害，接着通过“所以”总结前文，阐述消费者要提高自己的鉴别能力，有关方面也要普及增高常识。最后，通过程度词“更重要的是”强调治理增高乱象要给商家吃“罚药”，即加大对增高产品乱象的惩处力度，对应D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项，仅对应“消费者”，非重点，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，“对身体造成严重损害”为问题表述，而文段强调对策，非重点，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，仅对应“增高常识普及”，表述片面，且对应程度词之前的内容，非重点，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details>',24))])}const h=n(x,[["render",v]]);export{D as __pageData,h as default};
